let table: Array<[number, number]> | null = null;
function build(): Array<[number, number]> {
  const out: Array<[number, number]> = [];
  let prev = 0;
  for (const part of RANGES.split(",")) {
    const [d, len] = part.split(".").map((s) => parseInt(s, 16));
    const a = prev + d;
    out.push([a, a + len]);
    prev = a + len;
  }
  return out;
}
/** True when MS Mincho's cmap covers the code point (JIS repertoire). */
export function minchoCovers(cp: number): boolean {
  if (cp < 0x3400 || cp > 0xfaff) return true;
  if (!table) table = build();
  let lo = 0;
  let hi = table.length - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    const [a, b] = table[mid];
    if (cp < a) hi = mid - 1;
    else if (cp > b) lo = mid + 1;
    else return true;
  }
  return false;
}
